import warnings


class Utils:
    @staticmethod
    def to_overpass_id(osmid, area=False):
        if area:
            message = (
                "Utils.to_overpass_id(..., area=True) is deprecated and will be "
                "removed in overpass 1.0. Overpass API 0.7.57+ no longer supports "
                "legacy way-derived 2400xxx area IDs; query closed ways directly instead."
            )
        else:
            message = (
                "Utils.to_overpass_id(...) is deprecated and will be removed in "
                "overpass 1.0; use AreaId.from_relation(...) in 1.0 instead."
            )
        warnings.warn(message, DeprecationWarning, stacklevel=2)

        area_base = 2400000000
        relation_base = 3600000000
        if area:
            return int(osmid) + area_base
        return int(osmid) + relation_base
